function withHeaders(body: string, contentType: string, init: ResponseInit = {}): Response {
  const headers = new Headers(init.headers);
  headers.set("content-type", contentType);
  headers.set("cache-control", "public, max-age=300, s-maxage=300");
  headers.set("access-control-allow-origin", "*");
  headers.set("x-mmd-asset-version", VERSION);
  return new Response(body, { ...init, headers });
}

export default {
  async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url);
    if (request.method === "OPTIONS") {
      return withHeaders("", "text/plain; charset=utf-8", {
        headers: {
          "access-control-allow-methods": "GET,OPTIONS",
          "access-control-allow-headers": "content-type",
        },
      });
    }

    if (url.pathname === "/a/create-session.css") {
      return withHeaders(CSS, "text/css; charset=utf-8");
    }

    if (url.pathname === "/a/create-session.js") {
      return withHeaders(JS, "application/javascript; charset=utf-8");
    }

    if (url.pathname === "/a/create-session.version.json") {
      return withHeaders(JSON.stringify({ ok: true, version: VERSION }), "application/json; charset=utf-8");
    }

    return withHeaders("Not found", "text/plain; charset=utf-8", { status: 404 });
  },
};
